using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any existing messages from static queue (shared across tests)
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("TestUser", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("Chemistry", notification.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("42", notification.Message);
            Assert.Contains("updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
        {
            _service.SendNotification("Department", "5", "English", EntityOperation.DELETE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("deleted", notification.Message);
            Assert.Contains("English", notification.Message);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var result = _service.ReceiveNotification();
            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_DequesInFifoOrder()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("A", first!.EntityType);
            Assert.Equal("B", second!.EntityType);
        }

        [Fact]
        public void SendNotification_DefaultUser_IsSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification!.CreatedBy);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory, just verify no exception
            var ex = Record.Exception(() => _service.MarkAsRead(999));
            Assert.Null(ex);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification!.CreatedAt, before, after);
        }
    }
}

using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext(string? dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = DateTime.Parse("2019-09-01") },
                new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = DateTime.Parse("2017-09-01") },
                new Student { ID = 3, LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = DateTime.Parse("2018-09-01") }
            );
            context.SaveChanges();
        }

        public static void SeedDepartments(SchoolContext context)
        {
            context.Departments.AddRange(
                new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = null },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = null }
            );
            context.SaveChanges();
        }

        public static void SeedInstructors(SchoolContext context)
        {
            context.Instructors.AddRange(
                new Instructor { ID = 10, LastName = "Zheng", FirstMidName = "Roger", HireDate = DateTime.Parse("2004-02-12"), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { ID = 11, LastName = "Kapoor", FirstMidName = "Candace", HireDate = DateTime.Parse("2001-01-15"), CourseAssignments = new List<CourseAssignment>() }
            );
            context.SaveChanges();
        }

        public static void SeedCourses(SchoolContext context)
        {
            SeedDepartments(context);
            context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 }
            );
            context.SaveChanges();
        }

        public static void SeedAll(SchoolContext context)
        {
            SeedInstructors(context);
            SeedCourses(context);
            SeedStudents(context);
        }
    }
}

