using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedStudents(_context);
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index(null, null, null, null);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.True(model.Count > 0);
            // Default sort is LastName ascending
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_NameDescSort_OrdersByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Equal("Anand", model.First().LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            // Alonso has earliest date (2017)
            Assert.Equal("Alonso", model.First().LastName);
        }

        [Fact]
        public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            // Alexander has latest date (2019)
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchString_FiltersResults()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Alexander", model.First().LastName);
        }

        [Fact]
        public void Index_SearchByFirstName_FiltersResults()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
            Assert.Equal("Carson", model.First().FirstMidName);
        }

        [Fact]
        public void Index_SearchString_ResetsPageToOne()
        {
            var result = _controller.Index(null, null, "Alex", 5) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearch_UsesCurrentFilter()
        {
            var result = _controller.Index(null, "Alexander", null, null) as ViewResult;
            var model = result!.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            Assert.Single(model);
        }

        [Fact]
        public void Details_ValidId_ReturnsStudent()
        {
            var result = _controller.Details(1) as ViewResult;
            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithStudent()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            var student = new Student
            {
                LastName = "TestLast",
                FirstMidName = "TestFirst",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            var result = _controller.Create(student);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidStudent_AddsToDatabase()
        {
            var student = new Student
            {
                LastName = "NewStudent",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            };

            _controller.Create(student);
            Assert.True(_context.Students.Any(s => s.LastName == "NewStudent"));
        }

        [Fact]
        public void Create_Post_InvalidEnrollmentDate_ReturnsView()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student);
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.Equal(student, viewResult.Model);
        }

        [Fact]
        public void Create_Post_DateOutOfRange_ReturnsView()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = _controller.Create(student);
            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Edit(1) as ViewResult;
            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            var student = _context.Students.AsNoTracking().First(s => s.ID == 1);
            student.LastName = "UpdatedName";
            student.EnrollmentDate = DateTime.Parse("2020-01-01");

            var result = _controller.Edit(student);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidEnrollmentDate_ReturnsView()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            var result = _controller.Delete(1) as ViewResult;
            Assert.NotNull(result);
            var student = result.Model as Student;
            Assert.NotNull(student);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Students.Find(1));
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            var result = _controller.Index("Date", null, "test", null) as ViewResult;
            Assert.Equal("Date", _controller.ViewBag.CurrentSort);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
            Assert.Equal("test", _controller.ViewBag.CurrentFilter);
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempPath;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedCourses(_context);

            _tempPath = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempPath);

            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempPath);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempPath);

            _mockLogger = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempPath))
                Directory.Delete(_tempPath, true);
        }

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as System.Collections.Generic.List<Course>;
            Assert.NotNull(model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ValidId_ReturnsCourse()
        {
            var result = _controller.Details(1050) as ViewResult;
            Assert.NotNull(result);
            var course = result.Model as Course;
            Assert.NotNull(course);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            Assert.NotNull(result.Model);
        }

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null!);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidCourse_AddsToDatabase()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            };

            _controller.Create(course, null!);
            Assert.True(_context.Courses.Any(c => c.CourseID == 8888));
        }

        [Fact]
        public void Create_Post_WithValidImage_SavesFile()
        {
            var course = new Course
            {
                CourseID = 7777,
                Title = "Image Course",
                Credits = 2,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 1024);
            var result = _controller.Create(course, fileMock.Object);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);

            var saved = _context.Courses.Find(7777);
            Assert.NotNull(saved!.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_InvalidFileExtension_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 6666,
                Title = "Bad File Course",
                Credits = 2,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.exe", "application/octet-stream", 1024);
            var result = _controller.Create(course, fileMock.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
