                CourseID = 5555,
                Title = "Large File Course",
                Credits = 2,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024);
            var result = _controller.Create(course, fileMock.Object);

