using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.IO;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempPath;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedCourses(_context);

            _tempPath = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempPath);

            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempPath);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempPath);

            _mockLogger = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempPath))
                Directory.Delete(_tempPath, true);
        }

        [Fact]
        public void Index_ReturnsViewWithCourses()
        {
            var result = _controller.Index() as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as System.Collections.Generic.List<Course>;
            Assert.NotNull(model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ValidId_ReturnsCourse()
        {
            var result = _controller.Details(1050) as ViewResult;
            Assert.NotNull(result);
            var course = result.Model as Course;
            Assert.NotNull(course);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            Assert.NotNull(result.Model);
        }

        [Fact]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 4,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null!);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_ValidCourse_AddsToDatabase()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 1
            };

            _controller.Create(course, null!);
            Assert.True(_context.Courses.Any(c => c.CourseID == 8888));
        }

        [Fact]
        public void Create_Post_WithValidImage_SavesFile()
        {
            var course = new Course
            {
                CourseID = 7777,
                Title = "Image Course",
                Credits = 2,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 1024);
            var result = _controller.Create(course, fileMock.Object);

            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);

            var saved = _context.Courses.Find(7777);
            Assert.NotNull(saved!.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_InvalidFileExtension_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 6666,
                Title = "Bad File Course",
                Credits = 2,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.exe", "application/octet-stream", 1024);
            var result = _controller.Create(course, fileMock.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_FileTooLarge_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 5555,
                Title = "Large File Course",
                Credits = 2,
                DepartmentID = 1
            };

            var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024);
            var result = _controller.Create(course, fileMock.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 4444, Title = "", Credits = 3, DepartmentID = 1 };

            var result = _controller.Create(course, null!);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsCourse()
        {
            var result = _controller.Edit(1050) as ViewResult;
            Assert.NotNull(result);
            var course = result.Model as Course;
            Assert.NotNull(course);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
            course.Title = "Updated Chemistry";

            var result = _controller.Edit(course, null!);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, Title = "", Credits = 3, DepartmentID = 1 };

            var result = _controller.Edit(course, null!);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsCourse()
        {
            var result = _controller.Delete(1050) as ViewResult;
            Assert.NotNull(result);
            var course = result.Model as Course;
            Assert.NotNull(course);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1050);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Courses.Find(1050));
        }

        private static Mock<IFormFile> CreateMockFormFile(string fileName, string contentType, long length)
        {
            var fileMock = new Mock<IFormFile>();
            var content = new byte[Math.Min(length, 1024)];
            var ms = new MemoryStream(content);
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.ContentType).Returns(contentType);
            fileMock.Setup(f => f.Length).Returns(length);
            fileMock.Setup(f => f.OpenReadStream()).Returns(ms);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => ms.CopyTo(s));
            return fileMock;
        }
    }
}

