using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            TestHelpers.SeedAll(_context);

            // Add course assignments for instructor 10
            _context.CourseAssignments.Add(new CourseAssignment { InstructorID = 10, CourseID = 1050 });
            _context.SaveChanges();

            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_NoParams_ReturnsViewWithInstructors()
        {
            var result = _controller.Index(null, null) as ViewResult;
            Assert.NotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.NotNull(model);
            Assert.Equal(2, model.Instructors.Count());
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var result = _controller.Index(10, null) as ViewResult;
            var model = result!.Model as InstructorIndexData;
            Assert.NotNull(model!.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Details_ValidId_ReturnsInstructor()
        {
            var result = _controller.Details(10) as ViewResult;
            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.Equal("Zheng", instructor.LastName);
        }

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Details(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;
            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.NotNull(instructor.CourseAssignments);
        }

        [Fact]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstr",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null!);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "CourseInstr",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, new[] { "1050", "4022" });
            Assert.IsType<RedirectToActionResult>(result);
            var saved = _context.Instructors.Include(i => i.CourseAssignments)
                .First(i => i.LastName == "CourseInstr");
            Assert.Equal(2, saved.CourseAssignments.Count);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                LastName = "",
                FirstMidName = "Test",
                HireDate = DateTime.Now,
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null!);
            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsInstructor()
        {
            var result = _controller.Edit(10) as ViewResult;
            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.Equal("Zheng", instructor.LastName);
        }

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsInstructor()
        {
            var result = _controller.Delete(10) as ViewResult;
            Assert.NotNull(result);
            var instructor = result.Model as Instructor;
            Assert.NotNull(instructor);
            Assert.Equal("Zheng", instructor.LastName);
        }

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);
            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            var result = _controller.Delete(9999);
            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            // Add office assignment first
            _context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = 11, Location = "Office 1" });
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(11);
            var redirect = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirect.ActionName);
            Assert.Null(_context.Instructors.Find(11));
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            // Set instructor as department admin
            var dept = _context.Departments.First();
            dept.InstructorID = 11;
            _context.SaveChanges();

            _controller.DeleteConfirmed(11);

            var updatedDept = _context.Departments.First(d => d.DepartmentID == dept.DepartmentID);
            Assert.Null(updatedDept.InstructorID);
        }
    }
}

