using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "User",
                EnrollmentDate = DateTime.Parse("2020-01-01")
            };

            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First(s => s.LastName == "Test");
            Assert.Equal("User", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "Prof",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2015-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.First(i => i.LastName == "Prof");
            Assert.Equal("Test", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            _context.Departments.Add(new Department
            {
                DepartmentID = 100,
                Name = "TestDept",
                Budget = 100000,
                StartDate = DateTime.Now
            });
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 5001,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = 100
            };

            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.Find(5001);
            Assert.NotNull(retrieved);
            Assert.Equal("Test Course", retrieved.Title);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            var dept = new Department
            {
                Name = "TestDept",
                Budget = 50000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            _context.Departments.Add(dept);
            _context.SaveChanges();

            var retrieved = _context.Departments.First(d => d.Name == "TestDept");
            Assert.Equal(50000, retrieved.Budget);
        }

        [Fact]
        public void CanAddEnrollment()
        {
            var student = new Student
            {
                LastName = "EnrollTest",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Now
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            _context.Departments.Add(new Department { DepartmentID = 200, Name = "D", Budget = 1000, StartDate = DateTime.Now });
            _context.Courses.Add(new Course { CourseID = 6001, Title = "Enroll Course", Credits = 3, DepartmentID = 200 });
            _context.SaveChanges();

            var enrollment = new Enrollment
            {
                StudentID = student.ID,
                CourseID = 6001,
                Grade = Grade.A
            };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments.First(e => e.CourseID == 6001);
            Assert.Equal(Grade.A, retrieved.Grade);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            var instructor = new Instructor
            {
                LastName = "Key",
                FirstMidName = "Test",
                HireDate = DateTime.Now,
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            _context.Departments.Add(new Department { DepartmentID = 300, Name = "D3", Budget = 1000, StartDate = DateTime.Now });
            _context.Courses.Add(new Course { CourseID = 7001, Title = "Key Course", Credits = 3, DepartmentID = 300 });
            _context.SaveChanges();

            var assignment = new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = 7001
            };
            _context.CourseAssignments.Add(assignment);
            _context.SaveChanges();

            var retrieved = _context.CourseAssignments.Find(7001, instructor.ID);
            Assert.NotNull(retrieved);
        }

        [Fact]
        public void OfficeAssignment_OneToOneWithInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "Office",
                FirstMidName = "Test",
                HireDate = DateTime.Now,
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var office = new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Room 101"
            };
            _context.OfficeAssignments.Add(office);
            _context.SaveChanges();

            var retrieved = _context.OfficeAssignments.Find(instructor.ID);
            Assert.NotNull(retrieved);
            Assert.Equal("Room 101", retrieved.Location);
        }

        [Fact]
        public void CanAddNotification()
        {
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test",
                CreatedAt = DateTime.Now,
                CreatedBy = "System",
                IsRead = false
            };

            _context.Notifications.Add(notification);
            _context.SaveChanges();

            Assert.True(_context.Notifications.Any(n => n.EntityType == "Student"));
        }

        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student
            {
                LastName = "Inheritance",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Now
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            var person = _context.People.First(p => p.LastName == "Inheritance");
            Assert.IsType<Student>(person);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor
            {
                LastName = "InheritInstr",
                FirstMidName = "Test",
                HireDate = DateTime.Now,
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var person = _context.People.First(p => p.LastName == "InheritInstr");
            Assert.IsType<Instructor>(person);
        }

        [Fact]
        public void Person_FullName_ReturnsCombined()
        {
            var student = new Student
            {
                LastName = "Doe",
                FirstMidName = "John",
                EnrollmentDate = DateTime.Now
            };

            Assert.Equal("Doe, John", student.FullName);
        }
    }
}

